 10	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 11	import {
 12	  Form,
 13	  FormGroup,
 14	  Icon,
 15	  NumberInput,
 16	  Popover,
 17	  Stack,
 18	  StackItem,
 19	  ValidatedOptions,
 20	} from '@patternfly/react-core';
 21	import { HelpIcon } from '@patternfly/react-icons';
 22	
 23	import { CreateDataSourceModalFormType } from './CreateDataSourceModal';
 24	
 25	type CreateDataSourceFormProps = {
 26	  errors: {
 27	    [Property in keyof CreateDataSourceModalFormType]?: FieldError;
 28	  };
 29	  importsToKeep: number;
 30	  register: UseFormRegister<CreateDataSourceModalFormType>;
 31	  setValue: UseFormSetValue<CreateDataSourceModalFormType>;
 32	  size: string;
 33	};
 34	
 35	export const CreateDataSourceForm: FC<CreateDataSourceFormProps> = ({
 36	  errors,
 37	  importsToKeep,
 38	  register,
 39	  setValue,
 40	  size,
 41	}) => {
 42	  const { t } = useKubevirtTranslation();
 43	  return (
 44	    <Form>
 45	      <FormGroup fieldId="datasource-create-name" isRequired label={t('Name')}>
 46	        <FormTextInput
 47	          {...register('name', { required: true })}
 48	          aria-label={t('Name')}
 49	          data-test-id="datasource-create-name"
 50	          id="datasource-create-name"
 51	          type="text"
 52	          validated={errors?.['name'] ? ValidatedOptions.error : ValidatedOptions.default}
 53	        />
 54	        <FormGroupHelperText
 55	          validated={errors?.['name'] ? ValidatedOptions.error : ValidatedOptions.default}
 56	        >
 57	          {errors?.['name'] && t('This field is required')}
 58	        </FormGroupHelperText>
 59	      </FormGroup>
 60	      <FormGroup
 61	        aria-label={t('Registry URL')}
 62	        fieldId="datasource-create-source-url"
 63	        isRequired
 64	        label={t('Registry URL')}
 65	      >
 66	        <FormTextInput
 67	          {...register('url', { required: true })}
 68	          aria-label={t('Registry URL')}
 69	          data-test-id={'datasource-create-source-url'}
 70	          id={'datasource-create-source-url'}
 71	          type="text"
 72	          validated={errors?.['url'] ? ValidatedOptions.error : ValidatedOptions.default}
 73	        />
 74	        <FormGroupHelperText
 75	          validated={errors?.['url'] ? ValidatedOptions.error : ValidatedOptions.default}
 76	        >
 77	          {errors?.['url']
 78	            ? t('This field is required')
 79	            : t('Example: {{exampleURL}}', {
 80	                exampleURL: 'quay.io/containerdisks/centos:7-2009',
 81	              })}
 82	        </FormGroupHelperText>
 83	      </FormGroup>
 84	      <CapacityInput
 85	        label={t('Disk size')}
 86	        onChange={(value) => setValue('size', value)}
 87	        size={size}
 88	      />
 89	      <FormGroup
 90	        labelHelp={
 91	          <Popover
 92	            bodyContent={t(
 93	              'As new versions of a DataSource become available older versions will be replaced',
 94	            )}
 95	          >
 96	            <button
 97	              aria-describedby="retain-revision-info"
 98	              aria-label="More info for retain revisions field"
 99	              className="pf-v6-c-form__group-label-help"
100	              onClick={(e) => e.preventDefault()}
101	              type="button"
102	            >
103	              <Icon>
104	                <HelpIcon />
105	              </Icon>
106	            </button>
107	          </Popover>
108	        }
109	        fieldId="retain-revision-info"
110	        isRequired
111	        label={t('Retain revisions')}
112	      >
113	        <NumberInput
114	          id={'datasource-create-imports-to-keep'}
115	          max={10}
116	          min={0}
117	          onMinus={() => setValue('importsToKeep', importsToKeep - 1)}
118	          onPlus={() => setValue('importsToKeep', importsToKeep + 1)}
119	          value={importsToKeep}
120	        />
121	        <FormGroupHelperText>
122	          <Stack>
123	            <StackItem>
124	              <MutedTextSpan text={t('Specify the number of revisions that should be retained.')} />
125	            </StackItem>
126	            <StackItem>
127	              <MutedTextSpan
128	                text={t('A value of X means that the X latest versions will be kept')}
129	              />
130	            </StackItem>
131	          </Stack>
132	        </FormGroupHelperText>
133	      </FormGroup>
134	      <FormGroup fieldId="datasource-create-schedule" label={t('Scheduling settings')}>
135	        <FormGroupHelperText>
136	          <>
137	            {t('Schedule specifies in cron format when and how often to look for new imports.')}
138	            <ExternalLink href={documentationURL.CRON_INFO} text={t('Learn more')} />
139	          </>
140	        </FormGroupHelperText>
141	      </FormGroup>
142	      <FormGroup fieldId="datasource-create-cron" isRequired label={t('Cron expression')}>
143	        <FormTextInput
144	          {...register('schedule', {
145	            validate: {
146	              required: (value) => {
147	                if (!value) {
148	                  return t('Required when automatic update is enabled');
149	                }
150	                return true;
151	              },
152	            },
153	          })}
154	          aria-label={t('Cron expression')}
155	          data-test-id={'datasource-create-cron'}
156	          id={'datasource-create-source-cron'}
157	          isRequired
158	          type="text"
159	          validated={errors?.['schedule'] ? ValidatedOptions.error : ValidatedOptions.default}
160	        />
161	        <FormGroupHelperText
162	          validated={errors?.['schedule'] ? ValidatedOptions.error : ValidatedOptions.default}
163	        >
164	          {errors?.['schedule']
165	            ? t('This field is required')
166	            : t('Example (At 00:00 on Tuesday): {{exampleCron}}', {
167	                exampleCron: '0 0 * * 2',
168	              })}
169	        </FormGroupHelperText>
170	      </FormGroup>
171	    </Form>
172	  );
173	};

